// Generic CRUD operations
const create = async (req, res, tableName, columns) => {
  try {
    const values = columns.map(col => req.body[col]);
    const placeholders = values.map((_, index) => `$${index + 1}`).join(', ');
    const query = `INSERT INTO ${tableName} (${columns.join(', ')}) VALUES (${placeholders}) RETURNING *`;
    
    const result = await pool.query(query, values);
    res.status(201).json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

const read = async (req, res, tableName, idColumn = 'id') => {
  try {
    const id = req.params[idColumn];
    const query = `SELECT * FROM ${tableName} WHERE ${idColumn} = $1`;
    const result = await pool.query(query, [id]);
    
    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Record not found' });
    }
    
    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

const readAll = async (req, res, tableName) => {
  try {
    const query = `SELECT * FROM ${tableName}`;
    const result = await pool.query(query);
    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

const update = async (req, res, tableName, columns, idColumn = 'id') => {
  try {
    const id = req.params[idColumn];
    const setClause = columns.map((col, index) => `${col} = $${index + 1}`).join(', ');
    const values = columns.map(col => req.body[col]);
    values.push(id);
    
    const query = `UPDATE ${tableName} SET ${setClause} WHERE ${idColumn} = $${columns.length + 1} RETURNING *`;
    const result = await pool.query(query, values);
    
    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Record not found' });
    }
    
    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

const deleteRecord = async (req, res, tableName, idColumn = 'id') => {
  try {
    const id = req.params[idColumn];
    const query = `DELETE FROM ${tableName} WHERE ${idColumn} = $1 RETURNING *`;
    const result = await pool.query(query, [id]);
    
    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Record not found' });
    }
    
    res.json({ message: 'Record deleted successfully' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

